import{c as t,Q as n,j as s,m as a}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"How do I decommission an instance?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/decommission-instance.md","filePath":"guide/recipes/admin/decommission-instance.md","lastUpdated":1779094756000}'),i={name:"guide/recipes/admin/decommission-instance.md"};function o(r,e,c,l,d,m){return n(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="how-do-i-decommission-an-instance" tabindex="-1">How do I decommission an instance? <a class="header-anchor" href="#how-do-i-decommission-an-instance" aria-label="Permalink to &quot;How do I decommission an instance?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Platform Admin</strong> or <strong>Infra Ops</strong></p></div><p>Decommissioning takes an instance out of service so tenant placement stops sending traffic to it. It&#39;s a soft-delete — the record remains for audit, but the instance is excluded from operational dashboards.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Make sure no active tenants remain on the instance. Open <strong>Instances → &lt;instance&gt; → Tenants</strong> and migrate or delete everything still there.</li><li>From the instance detail page, click <strong>Decommission</strong> in the actions menu.</li><li>Type the confirmation string and click <strong>Confirm</strong>.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><ul><li>The instance moves to status <strong>Decommissioned</strong>.</li><li>New tenants cannot be created on it.</li><li>The instance is hidden from the default Instances view (filter by <strong>Decommissioned</strong> to see it).</li><li>Heartbeats are no longer expected — the underlying stack can be torn down.</li></ul><div class="warning custom-block"><p class="custom-block-title">Decommissioning blocks new traffic, not running tenants</p><p>If any tenants are still on this instance, decommission <strong>does not</strong> stop them from serving requests. You must move or delete tenants first.</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./create-instance">How do I create a new instance?</a></li></ul>',10)])])}const p=t(i,[["render",o]]);export{u as __pageData,p as default};
